import boto3, json

sqs = boto3.client("sqs", region_name="us-east-1")

# 1. Create the DLQ first
dlq = sqs.create_queue(
    QueueName="agent_jobs_dlq",
    Attributes={
        "MessageRetentionPeriod": str(14 * 86_400),  # 14 days
    }
)
dlq_url = dlq["QueueUrl"]
dlq_arn = sqs.get_queue_attributes(
    QueueUrl=dlq_url, AttributeNames=["QueueArn"]
)["Attributes"]["QueueArn"]

# 2. Create the main queue with a redrive policy pointing at the DLQ
main = sqs.create_queue(
    QueueName="agent_jobs",
    Attributes={
        "VisibilityTimeout":      "300",   # 5 min — must exceed max agent run time
        "MessageRetentionPeriod": str(4 * 86_400),
        "RedrivePolicy": json.dumps({
            "deadLetterTargetArn": dlq_arn,
            "maxReceiveCount":     "3",    # 3 attempts before DLQ
        }),
    }
)
main_url = main["QueueUrl"]
print(f"Main: {main_url}")
print(f"DLQ:  {dlq_url}")

from enum import Enum

class FailureClass(str, Enum):
    POISON_INPUT   = "poison_input"    # bad payload, will always fail
    TRANSIENT      = "transient"       # should succeed on replay
    QUOTA_EXCEEDED = "quota_exceeded"  # retry after quota reset
    UNKNOWN        = "unknown"

def classify_dlq_message(job: AgentJob, error_log: str | None) -> FailureClass:
    if error_log and "JSONDecodeError" in error_log:
        return FailureClass.POISON_INPUT
    if error_log and "RateLimitError" in error_log:
        return FailureClass.QUOTA_EXCEEDED
    if job.attempt == 1:
        return FailureClass.TRANSIENT   # failed on first try — likely transient
    return FailureClass.UNKNOWN


def inspect_dlq(max_messages: int = 10):
    """Read from DLQ and print a summary of each failed job."""
    resp = sqs.receive_message(
        QueueUrl=dlq_url,
        MaxNumberOfMessages=min(max_messages, 10),
        WaitTimeSeconds=1,
        AttributeNames=["All"],
    )
    for msg in resp.get("Messages", []):
        job = AgentJob(**json.loads(msg["Body"]))
        cls = classify_dlq_message(job, error_log=None)
        print(
            f"job_id={job.job_id}  attempts={job.attempt}  "
            f"class={cls}  tenant={job.tenant_id}  "
            f"created={job.created_at}"
        )
    return resp.get("Messages", [])
